class Solution(object):
    def checkValid(self, matrix):
        n = len(matrix)
        for row in matrix:
            if len(set(row)) != n or min(row) != 1 or max(row) != n:
                return False
        for j in range(n):
            col = [matrix[i][j] for i in range(n)]
            if len(set(col)) != n or min(col) != 1 or max(col) != n:
                return False
        return True
